var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"BOX_NPC_GAMECIRCLE_X","text":{"KOREA":"이게……. 우리들의 첫 게임……. 카운터즈 사가……?","JPN":"これが……僕たちの初のゲーム……カウンターズ・サーガ……？","ENG":"This is... our first game...! Counters Saga…","TWN":"這是……我們的第一個遊戲…… 制裁者傳奇……？"},"stage":{"bg":"GAMECIRCLE_02","bgm":"OFFICE_COMMON_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":"STAR_GAMECIRCLE_NULL_NULL","text":{"KOREA":"오호!? 쌔 삥이라 따끈따끈한데? 이 정도면 진짜로 대박 칠 거 같지 않나?","JPN":"おお！？　出来立てほやほややん！　これならホンマに大ヒットしそうやな？","ENG":"Aha! Hot off the press! This is going to be a show stopper for sure!","TWN":"哇喔！？是剛做好的嗎？還熱熱的呢？這應該會大賣吧？"},"stage":{"bg":"GAMECIRCLE_02","bgm":"OFFICE_COMMON_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":"DAIN_GAMECIRCLE_NULL_NULL","text":{"KOREA":"응응, 너무 귀엽게 나온 거 같아. 역시 박스 군은 대단해!","JPN":"うんうん、とてもかわいくできたと思う。やっぱりダンボール君はすごい！","ENG":"Yes, it’s so cute! You’re awesome, Boxie!","TWN":"嗯嗯，超可愛的，紙箱小朋友真的好厲害！"},"stage":{"bg":"GAMECIRCLE_02","bgm":"OFFICE_COMMON_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":"BOX_NPC_GAMECIRCLE_X","text":{"KOREA":"하하, 아니에요.","JPN":"はは、とんでもないです。","ENG":"Ha ha, thanks.","TWN":"哈哈，沒有啦。"},"stage":{"bg":"GAMECIRCLE_02","bgm":"OFFICE_COMMON_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":"BOX_NPC_GAMECIRCLE_X","text":{"KOREA":"SD 캐릭터는 자신 없었는데…… 그래도 실제로 프린팅된 걸 보니까 그럭저럭 잘 나온 것 같아서 기뻐요.","JPN":"SDキャラは自信なかったんですけど……でも実際にプリントされたのを見ると、まあまあの出来なので嬉しいです。","ENG":"I’m not too confident with SD art styles... But looking at how it got printed out, I guess it’s okay.","TWN":"SD角色我沒什麼把握……不過看到實際呈現後，成果很不錯呢，真開心。"},"stage":{"bg":"GAMECIRCLE_02","bgm":"OFFICE_COMMON_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":"STAR_GAMECIRCLE_NULL_NULL","text":{"KOREA":"뭐라노? 아무나 이렇게 못 그린다 안 카나. 이건 니만 할 수 있는 거라고.","JPN":"何言ってんねん。普通はこうは描けへんて。これはあんたにしかできへんよ。","ENG":"What's that ya say? It ain’t common bein’ able to draw like Picasso! That's somethin’ only you can do, kiddo.","TWN":"說啥呢？這可不是誰都畫得出來的，只有你可以。"},"stage":{"bg":"GAMECIRCLE_02","bgm":"OFFICE_COMMON_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L8_1","type":"dialog","speaker":"STAR_GAMECIRCLE_NULL_NULL","text":{"KOREA":"니는 좀 더 자신감을 가져도 된다! 마, 가슴도 좀 더 쫙 펴고!","JPN":"あんたはもっと自信持ちいや！　ほら、もっと胸張って！","ENG":"Whatcha need is some self-respect! Keep your chin up!","TWN":"你要對自己更有自信！抬頭挺胸！"},"stage":{"bg":"GAMECIRCLE_02","bgm":"OFFICE_COMMON_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L9_1","type":"dialog","speaker":"DAIN_GAMECIRCLE_NULL_NULL","text":{"KOREA":"아, 그럼 우리 타임 캡슐을 만들어 보는 거 어때?","JPN":"あ、じゃあタイムカプセルを作ってみるのはどう？","ENG":"Hey, why don’t we make a time capsule?","TWN":"這樣吧！不如做個時空膠囊怎麼樣？"},"stage":{"bg":"GAMECIRCLE_02","bgm":"OFFICE_COMMON_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L10_1","type":"dialog","speaker":"STAR_GAMECIRCLE_NULL_NULL","text":{"KOREA":"오오, 좋네! 나중에 어른이 되면 다 같이 모여가 열어보는기다! 약속이래이!","JPN":"おお、ええやん！　後で大人になったら、みんな集まって開けてみよ！　約束やで！","ENG":"Oh goodie! Y’all are goin’ to gather after we’ve grown up, and we’re gonna open this together! It’s a promise!","TWN":"喔喔，不錯喔！等長大後再一起打開來看！說好囉！"},"stage":{"bg":"GAMECIRCLE_02","bgm":"OFFICE_COMMON_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L11_1","type":"dialog","speaker":"BOX_NPC_GAMECIRCLE_X","text":{"KOREA":"……저도 좋아요.","JPN":"……僕も賛成です。","ENG":"...Cool with me as well.","TWN":"……我也同意。"},"stage":{"bg":"GAMECIRCLE_02","bgm":"OFFICE_COMMON_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L14_1","type":"dialog","speaker":"DAIN_GAMECIRCLE_NULL_NULL","text":{"KOREA":"얘들아. 말이 나와서 말인데, 혹시 너희들은 나중에 크면 뭐가 되고 싶어?","JPN":"みんな。その話のついでなんだけど、みんなは将来何になりたいの？","ENG":"Hey guys, while we're on the subject, what do you want to be when you grow up?","TWN":"說到這個，你們有想過長大後要做什麼嗎？"},"stage":{"bg":"CIRCLEROOM","bgm":"THEMA_GAMECIRCLE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DAIN_GAMECIRCLE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"STAR_GAMECIRCLE_NULL_NULL","text":{"KOREA":"내 말 안 해줬나? 당연히 쌤 곁에서…","JPN":"言わんかった？　当然先生のそばで……","ENG":"Didn't I say already? I'm gonna be next to Teach and–","TWN":"我沒說過嗎？當然是和老師一起…"},"stage":{"bg":"CIRCLEROOM","bgm":"THEMA_GAMECIRCLE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAR_GAMECIRCLE_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"BOX_NPC_GAMECIRCLE_X","text":{"KOREA":"응?","JPN":"うん？","ENG":"Hmm?","TWN":"嗯？"},"stage":{"bg":"CIRCLEROOM","bgm":"THEMA_GAMECIRCLE_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BOX_NPC_GAMECIRCLE_X","face":"UNIT_SERIOUS2"},"C":{"char_id":"STAR_GAMECIRCLE_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"STAR_GAMECIRCLE_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CIRCLEROOM","bgm":"THEMA_GAMECIRCLE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAR_GAMECIRCLE_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"STAR_GAMECIRCLE_NULL_NULL","text":{"KOREA":"내는… 카운터즈 사가를 최고로 만들기다!","JPN":"ウチ……最っ高のカウンターズ・サーガを作るんや！","ENG":"I'm gonna... make Counters Saga the best game ever!","TWN":"一起…製作最棒的制裁者傳奇！"},"stage":{"bg":"CIRCLEROOM","bgm":"THEMA_GAMECIRCLE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAR_GAMECIRCLE_NULL_NULL","face":"UNIT_PRIDE"},"R":null}},"sfx":"FX_CUTSCEN_TADA2"},{"id":"L24_1","type":"dialog","speaker":"BOX_NPC_GAMECIRCLE_X","text":{"KOREA":"엥? 똑같은 게임을 또 만드시게요?","JPN":"えっ？　同じゲームをまた作るんですか？","ENG":"Huh? You're going to make the same game again?","TWN":"蛤？你要做一個一樣的遊戲？"},"stage":{"bg":"CIRCLEROOM","bgm":"THEMA_GAMECIRCLE_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"STAR_GAMECIRCLE_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"BOX_NPC_GAMECIRCLE_X","face":"UNIT_SERIOUS2"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L25_1","type":"dialog","speaker":"STAR_GAMECIRCLE_NULL_NULL","text":{"KOREA":"그런 말이 아니고….","JPN":"そうちゃうて……","ENG":"That's not what I'm sayin'...","TWN":"不是這個意思…"},"stage":{"bg":"CIRCLEROOM","bgm":"THEMA_GAMECIRCLE_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"STAR_GAMECIRCLE_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"BOX_NPC_GAMECIRCLE_X","face":"UNIT_SERIOUS2"}}}},{"id":"L27_1","type":"dialog","speaker":"STAR_GAMECIRCLE_NULL_NULL","text":{"KOREA":"내는 게임 회사 사장이 될 기다!","JPN":"ウチはゲーム会社の社長になる！","ENG":"I'm gonna become a CEO of a game company!","TWN":"我要成為遊戲公司的老闆！"},"stage":{"bg":"CIRCLEROOM","bgm":"THEMA_GAMECIRCLE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAR_GAMECIRCLE_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"STAR_GAMECIRCLE_NULL_NULL","text":{"KOREA":"카운터즈 사가를 대박 내가, 후속작도 내고, 영화도 내고 만화도 다 만들어볼 기다!","JPN":"カウンターズ・サーガを大ヒットさせて、その続編出して、映画もマンガも全部作るんや！","ENG":"Counters Saga is gonna be a huge hit, releasing a sequel, and licensing it out to make movies and comics and all!","TWN":"我要讓制裁者傳奇大賣，然後再出續作，還要出電影，漫畫也要出！"},"stage":{"bg":"CIRCLEROOM","bgm":"THEMA_GAMECIRCLE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAR_GAMECIRCLE_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"BOX_NPC_GAMECIRCLE_X","text":{"KOREA":"게임 회사인데 왜 영화에 만화까지 만들어요?","JPN":"ゲーム会社なのに、どうして映画やマンガまで？","ENG":"Why would a game company make movies and comics?","TWN":"遊戲公司幹嘛出電影跟漫畫？"},"stage":{"bg":"CIRCLEROOM","bgm":"THEMA_GAMECIRCLE_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"STAR_GAMECIRCLE_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"BOX_NPC_GAMECIRCLE_X","face":"UNIT_SERIOUS2"}}}},{"id":"L32_1","type":"dialog","speaker":"STAR_GAMECIRCLE_NULL_NULL","text":{"KOREA":"성공하면 뭐든지 가능한 거 모르나. 그럼 박스 니는 커서 뭐가 되고 싶은데?","JPN":"一発成功させたら、何でもいけるって。ほんならダンボール、あんたは何になりたい？","ENG":"Don't ya know everythin' is possible when you're successful? Then, whaddya wanna be when you grow up, Boxie?","TWN":"只要大賣我想出什麼就出什麼！那不然紙箱你說說看，你長大要做什麼？"},"stage":{"bg":"CIRCLEROOM","bgm":"THEMA_GAMECIRCLE_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"STAR_GAMECIRCLE_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"BOX_NPC_GAMECIRCLE_X","face":"UNIT_SERIOUS2"}}}},{"id":"L34_1","type":"dialog","speaker":"BOX_NPC_GAMECIRCLE_X","text":{"KOREA":"저, 저요?","JPN":"ぼ、僕ですか？","ENG":"M-me?","TWN":"我，我嗎？"},"stage":{"bg":"CIRCLEROOM","bgm":"THEMA_GAMECIRCLE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BOX_NPC_GAMECIRCLE_X","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"BOX_NPC_GAMECIRCLE_X","text":{"KOREA":"음…. 아무래도 프리랜서 쪽으로 생각하고 있어요.","JPN":"うーん……フリーランサーかなって思ってますね。","ENG":"Mm.... I was thinking of working as a freelancer.","TWN":"嗯…我想當自由工作者。"},"stage":{"bg":"CIRCLEROOM","bgm":"THEMA_GAMECIRCLE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BOX_NPC_GAMECIRCLE_X","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"BOX_NPC_GAMECIRCLE_X","text":{"KOREA":"평범한 샐러리맨으로 살기엔 인생이 너무 아깝잖아요.","JPN":"普通のサラリーマンって、人生がもったいないじゃないですか。","ENG":"There's so much in life to waste it in being a normal salaryman.","TWN":"只當一個平凡的上班族不是很浪費生命嗎？"},"stage":{"bg":"CIRCLEROOM","bgm":"THEMA_GAMECIRCLE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BOX_NPC_GAMECIRCLE_X","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"STAR_GAMECIRCLE_NULL_NULL","text":{"KOREA":"오~ 박스 네가 벌써부터 나중 일을 생각했나?","JPN":"お～ダンボール、あんたもう先のこと考えてたんか？","ENG":"Ooh! You're already thinkin' about the future?","TWN":"哇喔～紙箱，你現在就已經在想將來的事啦？"},"stage":{"bg":"CIRCLEROOM","bgm":"THEMA_GAMECIRCLE_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"STAR_GAMECIRCLE_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"BOX_NPC_GAMECIRCLE_X","face":"UNIT_IDLE"}}}},{"id":"L40_1","type":"dialog","speaker":"STAR_GAMECIRCLE_NULL_NULL","text":{"KOREA":"하긴 네가 평범한 회사가가, 상사한테 굽신대는 모습은 상상이 안 가긴 하네.","JPN":"まあ、確かにあんたが普通の会社で上司にペコペコしてる姿は想像つかんな。","ENG":"I guess you're right. I can't imagine seein' you bowin' down to your boss in an ordinary company.","TWN":"確實啦，好難想像你在公司對主管鞠躬哈腰的樣子。"},"stage":{"bg":"CIRCLEROOM","bgm":"THEMA_GAMECIRCLE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAR_GAMECIRCLE_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"BOX_NPC_GAMECIRCLE_X","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L42_1","type":"dialog","speaker":"BOX_NPC_GAMECIRCLE_X","text":{"KOREA":"아니, 누나들이 먼저 물어봐 놓고선!","JPN":"いや、そっちから先に聞いてきたんじゃないですか！","ENG":"Hey, you're the one who asked me first!","TWN":"明明你們先起頭的，自己又不說！"},"stage":{"bg":"CIRCLEROOM","bgm":"THEMA_GAMECIRCLE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BOX_NPC_GAMECIRCLE_X","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"STAR_GAMECIRCLE_NULL_NULL","text":{"KOREA":"다인이는 뭐가 될 생각이고?","JPN":"タエは？","ENG":"What about you, Dain?","TWN":"妲茵你呢？"},"stage":{"bg":"CIRCLEROOM","bgm":"THEMA_GAMECIRCLE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAR_GAMECIRCLE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"DAIN_GAMECIRCLE_NULL_NULL","text":{"KOREA":"음~ 글쎄….","JPN":"う～ん、どうかな……","ENG":"Um, I don't know…","TWN":"嗯～不知道欸…"},"stage":{"bg":"CIRCLEROOM","bgm":"THEMA_GAMECIRCLE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DAIN_GAMECIRCLE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"STAR_GAMECIRCLE_NULL_NULL","text":{"KOREA":"아하하, 네가 먼저 물어봐 놓고, 정작 자기는 생각 안 해봤나?","JPN":"あはは、自分から聞いといて、何も考えてへんかったん？","ENG":"Ah hah hah! You asked us first and you never thought 'bout it?","TWN":"哈哈哈，是你先問大家的，結果自己卻沒想過嗎？"},"stage":{"bg":"CIRCLEROOM","bgm":"THEMA_GAMECIRCLE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAR_GAMECIRCLE_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"DAIN_GAMECIRCLE_NULL_NULL","text":{"KOREA":"아, 아냐. 난 그냥….","JPN":"ち、違うよ。私はただ……","ENG":"N-no. I just...","TWN":"沒，沒有啦，我只是…"},"stage":{"bg":"CIRCLEROOM","bgm":"THEMA_GAMECIRCLE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DAIN_GAMECIRCLE_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"BOX_NPC_GAMECIRCLE_X","text":{"KOREA":"선생님은 어때요? 전부터 느꼈는데 다인이 누난 아이들을 잘 돌보실 것 같아요.","JPN":"前から考えてたんですけど、タエさんは子どもの世話が上手そうですから、先生とかはどうですか？","ENG":"What about becoming a teacher? I think you'll be good at taking care of kids, Dain.","TWN":"當老師怎麼樣？我之前就覺得妲茵姊姊很會照顧小朋友。"},"stage":{"bg":"CIRCLEROOM","bgm":"THEMA_GAMECIRCLE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DAIN_GAMECIRCLE_NULL_NULL","face":"UNIT_SURPRISE"},"R":{"char_id":"BOX_NPC_GAMECIRCLE_X","face":"UNIT_SERIOUS2"}}}},{"id":"L2_1","type":"dialog","speaker":"BOX_NPC_GAMECIRCLE_X","text":{"KOREA":"그… 미술 선생님만 아니라면….","JPN":"その……美術の先生じゃないなら……","ENG":"Well... as long as you don't become an art teacher...","TWN":"只要…不是美術老師就好…"},"stage":{"bg":"CIRCLEROOM","bgm":"THEMA_GAMECIRCLE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DAIN_GAMECIRCLE_NULL_NULL","face":"UNIT_SURPRISE"},"R":{"char_id":"BOX_NPC_GAMECIRCLE_X","face":"UNIT_SERIOUS2"}}}},{"id":"L5_1","type":"dialog","speaker":"DAIN_GAMECIRCLE_NULL_NULL","text":{"KOREA":"흠… 생각도 안 해봤는걸? 아이들이 날 좋아해 줄지 잘 모르겠고.","JPN":"うーん……考えたことなかったな。子どもに好かれるかわからないし。","ENG":"Hmm... I never thought about that before. And I don't know if the students will like me.","TWN":"喔…我都沒想過呢？小朋友會喜歡我嗎？"},"stage":{"bg":"CIRCLEROOM","bgm":"THEMA_GAMECIRCLE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DAIN_GAMECIRCLE_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"DAIN_GAMECIRCLE_NULL_NULL","text":{"KOREA":"있지… 난 너희들과 함께 계속 게임 만드는 일을 하고 싶어.","JPN":"あのね……私はあなたたちと一緒にずっとゲームを作りたいよ。","ENG":"You know what...? I want to work with you all and keep making games.","TWN":"我想到了…我想繼續和你們一起做遊戲。"},"stage":{"bg":"CIRCLEROOM","bgm":"THEMA_GAMECIRCLE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DAIN_GAMECIRCLE_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"DAIN_GAMECIRCLE_NULL_NULL","text":{"KOREA":"나중에 어른이 되더라도 우린… 언제나 함께였으면 좋겠어.","JPN":"大人になっても私たちは……いつも一緒にいたいよ。","ENG":"Even after we become adults... I hope we'll still be together.","TWN":"我希望就算我們變成大人後…也可以像現在這樣永遠在一起。"},"stage":{"bg":"CIRCLEROOM","bgm":"THEMA_GAMECIRCLE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DAIN_GAMECIRCLE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"STAR_GAMECIRCLE_NULL_NULL","text":{"KOREA":"가, 갑자기 뭔 소리 하노? 남사스럽게 시리….","JPN":"い、いきなりなんや？　こっ恥ずかしい……","ENG":"W-what are ya sayin'? You're embarrassing me...","TWN":"你，突然說啥呢？害人家臉紅心跳的…"},"stage":{"bg":"CIRCLEROOM","bgm":"THEMA_GAMECIRCLE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAR_GAMECIRCLE_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"STAR_GAMECIRCLE_NULL_NULL","text":{"KOREA":"우리 넷은 언제나 함께다! 그건 앞으로도 영원할 거니까 걱정 붙들어 매라!","JPN":"ウチら四人はずっと一緒やで！　それはこれからも変わらんから心配すんな！","ENG":"The four of us will always be together forever! I know this for a fact, so don't you worry 'bout it!","TWN":"我們四個要一直在一起！以後也是，所以你放心吧！"},"stage":{"bg":"CIRCLEROOM","bgm":"THEMA_GAMECIRCLE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAR_GAMECIRCLE_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_CUTSCEN_TADA2"},{"id":"L12_1","type":"dialog","speaker":"BOX_NPC_GAMECIRCLE_X","text":{"KOREA":"누나…….","JPN":"マリさん……","ENG":"Rinae...","TWN":"姊姊……"},"stage":{"bg":"CIRCLEROOM","bgm":"THEMA_GAMECIRCLE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BOX_NPC_GAMECIRCLE_X","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"DAIN_GAMECIRCLE_NULL_NULL","text":{"KOREA":"후훗. 정말 고마워.","JPN":"ふふっ。本当にありがとうね。","ENG":"Ha ha. Thanks.","TWN":"呵呵，璃奈，謝謝你。"},"stage":{"bg":"CIRCLEROOM","bgm":"THEMA_GAMECIRCLE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DAIN_GAMECIRCLE_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"DAIN_GAMECIRCLE_NULL_NULL","text":{"KOREA":"리네가 차린 회사에 들어가는 것도 나쁘지 않겠네.","JPN":"マリちゃんの会社に入社するのも悪くなさそう。","ENG":"I think working in Rinae's company isn't such a bad idea.","TWN":"去你公司上班好像也蠻不錯的。"},"stage":{"bg":"CIRCLEROOM","bgm":"THEMA_GAMECIRCLE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DAIN_GAMECIRCLE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"STAR_GAMECIRCLE_NULL_NULL","text":{"KOREA":"오~ 그래! 다인이는 당연히 받아줘야제!","JPN":"お～そうや！　タエは合格！","ENG":"Yeah! You're welcome to join anytime, Dain!","TWN":"喔～沒問題！妲茵絕對錄取的！"},"stage":{"bg":"CIRCLEROOM","bgm":"THEMA_GAMECIRCLE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAR_GAMECIRCLE_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"STAR_GAMECIRCLE_NULL_NULL","text":{"KOREA":"너희 셋 다 나중에 크면 일 걱정은 하지 말그래이! 내 한자리씩 다 챙겨줄게!","JPN":"あんたたち三人とも、仕事の心配せんでええよ！　ウチがみんな雇ったる！","ENG":"Now, don't y'all three worry about no jobs, aight? I'll have a position for each of ya!","TWN":"你們三個以後不用怕找不到工作！全都來我公司上班唄！"},"stage":{"bg":"CIRCLEROOM","bgm":"THEMA_GAMECIRCLE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAR_GAMECIRCLE_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"BOX_NPC_GAMECIRCLE_X","text":{"KOREA":"아니 그건 비리잖아요…….","JPN":"いや、それはコネ入社じゃないですか……","ENG":"But that's corporate corruption...","TWN":"這是黑箱作業吧……"},"stage":{"bg":"CIRCLEROOM","bgm":"THEMA_GAMECIRCLE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAR_GAMECIRCLE_NULL_NULL","face":"UNIT_PRIDE"},"R":{"char_id":"BOX_NPC_GAMECIRCLE_X","face":"UNIT_SERIOUS2"}}}},{"id":"L22_1","type":"dialog","speaker":"DAIN_GAMECIRCLE_NULL_NULL","text":{"KOREA":"보라야, 너는? 넌 커서 뭐가 되고 싶어?","JPN":"シホちゃん、あなたは？　何になりたいの？","ENG":"Bora, what about you? What do you want to do when you grow up?","TWN":"寶拉，那你呢？你長大後要做什麼？"},"stage":{"bg":"CIRCLEROOM","bgm":"THEMA_GAMECIRCLE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DAIN_GAMECIRCLE_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"BORA_GAMECIRCLE_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CIRCLEROOM","bgm":"THEMA_GAMECIRCLE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BORA_GAMECIRCLE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"BORA_GAMECIRCLE_NULL_NULL","text":{"KOREA":"다인아……. 미안한데.","JPN":"タエ……悪いけど。","ENG":"Dain... I’m really sorry, but...","TWN":"妲茵……對不起，"},"stage":{"bg":"CIRCLEROOM","bgm":"THEMA_GAMECIRCLE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BORA_GAMECIRCLE_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"BORA_GAMECIRCLE_NULL_NULL","text":{"KOREA":"문제가 생겼어……. 중대한 문제.","JPN":"問題が起きた……重大な問題。","ENG":"We have a problem... A big problem.","TWN":"發生……大問題。"},"stage":{"bg":"CIRCLEROOM","bgm":"THEMA_GAMECIRCLE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BORA_GAMECIRCLE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"DAIN_GAMECIRCLE_NULL_NULL","text":{"KOREA":"응? 뭐가?","JPN":"え？　なにが？","ENG":"Hmm? What is it?","TWN":"嗯？什麼問題？"},"stage":{"bg":"CIRCLEROOM","bgm":"THEMA_GAMECIRCLE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DAIN_GAMECIRCLE_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"BORA_GAMECIRCLE_NULL_NULL","text":{"KOREA":"쌓여있잖아……. <color=#ffd34c>업무</color>…….","JPN":"積まれてる……<color=#ffd34c>業務</color>……","ENG":"It’s stacked up high... <color=#ffd34c>Our work</color>...","TWN":"堆好多，…… <color=#ffd34c>工作</color>……"},"stage":{"bg":"CIRCLEROOM","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BORA_GAMECIRCLE_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}},"sfx":"FX_CUTSCEN_TADA2"},{"id":"L32_1","type":"dialog","speaker":"DAIN_GAMECIRCLE_NULL_NULL","text":{"KOREA":"갑자기 그게 무슨 소리야? 우리 개발 다 끝났잖아.","JPN":"急に何言ってるの？　私たち、開発は全部終わってるよ？","ENG":"What are you talking about? We finished the game already.","TWN":"你在說什麼？遊戲不是都已經完成了嗎？"},"stage":{"bg":"CIRCLEROOM","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DAIN_GAMECIRCLE_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"BORA_PROMISE_NULL_NPC","text":{"KOREA":"이사장님. 혹시 주무시고 계신가요?","JPN":"理事長。もしかして、眠ってらっしゃるのですか？","ENG":"Ms. Chairwoman? Are you sleeping by chance?","TWN":"理事長，你在睡覺嗎？"},"stage":{"bg":"CIRCLEROOM","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_COMBAT_ALL_MAGIC_SPELL_LIGHT_02"},{"id":"L35_1","type":"dialog","speaker":"DAIN_GAMECIRCLE_NULL_NULL","text":{"KOREA":"이, 이사장…? 내가?","JPN":"り、理事長……？　私が？","ENG":"M-Ms. Chairwoman...? Me?","TWN":"理，理事長…？你說我？"},"stage":{"bg":"CIRCLEROOM","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DAIN_GAMECIRCLE_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"DAIN_GAMECIRCLE_NULL_NULL","text":{"KOREA":"아하하, 난 그런 쪽은 아직 생각해 보지 않았다니까 그러네.","JPN":"あはは、私はまだそこまでは考えてないってば。","ENG":"Ah hah hah. You know I haven't thought about becoming one yet.","TWN":"哈哈，我都沒想過要當理事長呢。"},"stage":{"bg":"CIRCLEROOM","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DAIN_GAMECIRCLE_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"BORA_PROMISE_NULL_NPC","text":{"KOREA":"이사장님.","JPN":"理事長。","ENG":"Ms. Chairwoman.","TWN":"理事長。"},"stage":{"bg":"CIRCLEROOM","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_COMBAT_ALL_MAGIC_SPELL_LIGHT_02"},{"id":"L40_1","type":"dialog","speaker":"DAIN_GAMECIRCLE_NULL_NULL","text":{"KOREA":"어, 어…?!","JPN":"え、ええ……！？","ENG":"H-huh...?","TWN":"嗯，嗯…？！"},"stage":{"bg":"CIRCLEROOM","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DAIN_GAMECIRCLE_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"이사장님.","JPN":"理事長。","ENG":"Ms. Chairwoman.","TWN":"理事長。"},"stage":{"bg":"CIRCLEROOM","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L47_1","type":"dialog","speaker":"PRESIDENT_PROMISE_NULL_NPC","text":{"KOREA":"앗?!","JPN":"あっ！？","ENG":"Oh?!","TWN":"啊？！"},"stage":{"bg":"CIRCLEROOM","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_PROMISE_NULL_NPC","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"죄송합니다. 많이 피곤하셨나요?","JPN":"申し訳ありません。お疲れなのですか？","ENG":"I'm sorry for waking you up. Should I come back later?","TWN":"抱歉，理事長是不是很累？"},"stage":{"bg":"CIRCLEROOM","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRESIDENT_PROMISE_NULL_NPC","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L1_1","type":"dialog","speaker":"PRESIDENT_PROMISE_NULL_NPC","text":{"KOREA":"아… 내가 깜빡 잠들었구나…. 정말 미안해.","JPN":"あ……私、うっかり寝てしまってたのね……本当にごめん。","ENG":"Oh... I guess I fell asleep... I'm sorry.","TWN":"啊…我睡著了…抱歉抱歉。"},"stage":{"bg":"CIRCLEROOM","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRESIDENT_PROMISE_NULL_NPC","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L2_1","type":"dialog","speaker":"PRESIDENT_PROMISE_NULL_NPC","text":{"KOREA":"할로윈 행사 때문에 찾아온 거 맞지?","JPN":"ハロウィンの件で話があるんでしょう？","ENG":"You're here because of the Halloween event, right?","TWN":"你來找我是要說萬聖節活動的事吧？"},"stage":{"bg":"CIRCLEROOM","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRESIDENT_PROMISE_NULL_NPC","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L3_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"네. 진행은 순조롭습니다. 올해도 성황이에요.","JPN":"はい。状況は順調です。今年も盛況ですね。","ENG":"Yes. It's going smoothly. It will be a success this year as well.","TWN":"是的，目前活動都進行得很順利，今年也非常熱鬧呢。"},"stage":{"bg":"CIRCLEROOM","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRESIDENT_PROMISE_NULL_NPC","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L4_1","type":"dialog","speaker":"PRESIDENT_PROMISE_NULL_NPC","text":{"KOREA":"올해는 시뮬레이션 이벤트가 없어서 아쉬워하는 학생들이 보이던데…….","JPN":"今年はシミュレーションイベントがなくて残念だって言う生徒がいたけど……","ENG":"Some of the students are disappointed that there is no simulation event this year...","TWN":"好像有些學生因為今年沒有模擬活動覺得很遺憾呢……"},"stage":{"bg":"CIRCLEROOM","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRESIDENT_PROMISE_NULL_NPC","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L5_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"저번 크리스마스 때 반응이 좋았기에 기대하는 학생들이 많더군요.","JPN":"去年のクリスマスにすごく反応がよかったので、期待していた生徒が多かったのです。","ENG":"I assume that many were looking forward to it after the positive response it received last Christmas.","TWN":"上次聖誕節的時候反應很好，所以學生們都很期待。"},"stage":{"bg":"CIRCLEROOM","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRESIDENT_PROMISE_NULL_NPC","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L6_1","type":"dialog","speaker":"PRESIDENT_PROMISE_NULL_NPC","text":{"KOREA":"곧 <color=#ffd34c>대규모 업데이트</color>가 있을 예정이니 어쩔 수 없지.","JPN":"もうすぐ<color=#ffd34c>大規模なアップデート</color>がある予定だから仕方ないわ。","ENG":"There's a <color=#ffd34c>major update</color> coming soon, so there's nothing we can do about that.","TWN":"但也沒辦法，剛好卡到<color=#ffd34c>大改版</color>的時間。"},"stage":{"bg":"CIRCLEROOM","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRESIDENT_PROMISE_NULL_NPC","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L7_1","type":"dialog","speaker":"PRESIDENT_PROMISE_NULL_NPC","text":{"KOREA":"개발기간이 행사 날과 겹쳐서 유감이야. 최대한 빨리 끝나야 할 텐데….","JPN":"開発期間がイベントの日と重なって残念ね。なるべく早く終わらせないと……","ENG":"It's a shame that the development period had to overlap with the event. It needs to be finished as soon as possible...","TWN":"因為開發時間和活動時間重疊到，只好忍痛放棄。必須要盡快完成才行…"},"stage":{"bg":"CIRCLEROOM","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRESIDENT_PROMISE_NULL_NPC","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L8_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"아참, 마침 그것 때문입니다만…….","JPN":"あっ、ちょうどその件なのですが……","ENG":"Oh, right. That's why I came to see you...","TWN":"對了，順便跟理事長報告一下……"},"stage":{"bg":"CIRCLEROOM","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRESIDENT_PROMISE_NULL_NPC","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L9_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"내일 협업사의 <color=#ffd34c>개발자</color> 분이 직접 방문하신다는군요.","JPN":"明日、協力会社の<color=#ffd34c>開発者</color>が直接、来訪されるそうです。","ENG":"Tomorrow, a <color=#ffd34c>developer</color> from our partner company will be visiting in person.","TWN":"明天合作公司的<color=#ffd34c>製作人</color>會親自造訪。"},"stage":{"bg":"CIRCLEROOM","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRESIDENT_PROMISE_NULL_NPC","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"이사장님과 그쪽 관계자분들끼리만 함께 베타 테스트를 진행하길 원하셨어요.","JPN":"理事長とあちらの関係者だけで、一緒にベータテストを行いたいとのことです。","ENG":"She said she wanted the beta testing to only be done by you and their staff.","TWN":"對方希望測試時，只有理事長和他們的相關人員在場。"},"stage":{"bg":"CIRCLEROOM","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRESIDENT_PROMISE_NULL_NPC","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"PRESIDENT_PROMISE_NULL_NPC","text":{"KOREA":"음… 알았어. 신중하게 하려는 거겠지.","JPN":"うーん……わかったわ。慎重にいきたいのね。","ENG":"Mm... All right. I guess she's probably trying to be careful.","TWN":"嗯…好，應該是想要謹慎一點吧。"},"stage":{"bg":"CIRCLEROOM","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRESIDENT_PROMISE_NULL_NPC","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"PRESIDENT_PROMISE_NULL_NPC","text":{"KOREA":"할로윈 날에 일하게 해서 미안해. 옌이 있어 줘서 정말 든든하단다.","JPN":"ハロウィンなのに仕事をさせちゃってごめんね。イェンさんがいてくれて本当に助かるわ。","ENG":"I'm sorry to make you work on Halloween. But it's reassuring to have you here, Yen.","TWN":"抱歉，萬聖節還讓你工作，有你在真的很安心呢。"},"stage":{"bg":"CIRCLEROOM","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRESIDENT_PROMISE_NULL_NPC","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"아뇨. 신경 쓰지 마시길.","JPN":"いいえ。お気になさらず。","ENG":"Please, don't mind me.","TWN":"沒事的，理事長不用多心。"},"stage":{"bg":"CIRCLEROOM","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRESIDENT_PROMISE_NULL_NPC","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L14_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"표정이 좋아 보이시네요. 좋은 일이라도 있으셨나요?","JPN":"表情が明るいですね。いいことでもあったのですか？","ENG":"You look happy today. Did anything good happen?","TWN":"我看理事長的表情好像很開心，是有發生什麼好事嗎？"},"stage":{"bg":"CIRCLEROOM","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRESIDENT_PROMISE_NULL_NPC","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"PRESIDENT_PROMISE_NULL_NPC","text":{"KOREA":"사실… 오늘 만날 개발자가 내 <color=#ffd34c>친구</color>거든.","JPN":"実は……今日会う開発者が私の<color=#ffd34c>友だち</color>なの。","ENG":"Well... the developer we're meeting with today is actually a <color=#ffd34c>friend</color> of mine.","TWN":"其實…今天要來的那位製作人是我的<color=#ffd34c>朋友</color>。"},"stage":{"bg":"CIRCLEROOM","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_PROMISE_NULL_NPC","face":"UNIT_LAUGH"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"PRESIDENT_PROMISE_NULL_NPC","text":{"KOREA":"서로 바쁘다 보니 요즘 만날 시간이 없었는데, 너무 설레네.","JPN":"お互い忙しくて最近会えなかったのよ、だからすごく楽しみね。","ENG":"We were both so busy that we couldn't make time to meet each other. So, I'm excited to meet her today.","TWN":"因為我們都很忙，所以最近都沒什麼時間見面，我現在有點興奮呢。"},"stage":{"bg":"CIRCLEROOM","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_PROMISE_NULL_NPC","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"그러셨군요. 이사장님의 밝은 표정을 보는 건 오랜만이네요.","JPN":"そうだったのですか。理事長の明るいお顔は久しぶりです。","ENG":"I see. It's been a long time since I saw you gleaming with joy, Ms. Chairwoman.","TWN":"原來是這樣，好久沒看到理事長開心的表情了。"},"stage":{"bg":"CIRCLEROOM","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"그럼 시간이 되면 다시 찾아오겠습니다.","JPN":"では、時間になったらまた来ます。","ENG":"Then, I will come back when it's time.","TWN":"那我之後再過來。"},"stage":{"bg":"CIRCLEROOM","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"PRESIDENT_PROMISE_NULL_NPC","text":{"KOREA":"응. 푹 쉬렴.","JPN":"うん。ゆっくり休みなさい。","ENG":"Okay. Rest well.","TWN":"好，去休息吧。"},"stage":{"bg":"CIRCLEROOM","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_PROMISE_NULL_NPC","face":"UNIT_LAUGH"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"PRESIDENT_PROMISE_NULL_NPC","text":{"KOREA":"좋아. 빨리 서류작업부터 해놔야겠다.","JPN":"よし。早く書類から片付けよう。","ENG":"All right. I need to get all the paperwork done.","TWN":"好，就先從文件開始處理吧。"},"stage":{"bg":"CIRCLEROOM","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_PROMISE_NULL_NPC","face":"UNIT_PRIDE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE"}]`);export{e as default};